# CONVERSION FUNCTIONS
# =============================================================================


def _incident_to_nested(incident: Incident) -> IncidentNested:
    """Convert flat Incident to nested format."""
    attrs = IncidentAttributes()
    _populate_incident_attrs(attrs, incident)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        incident, _INCIDENT_REL_FIELDS, IncidentRelationshipAttributes
    )
    return IncidentNested(
        guid=incident.guid,
        type_name=incident.type_name,
        status=incident.status,
        version=incident.version,
        create_time=incident.create_time,
        update_time=incident.update_time,
        created_by=incident.created_by,
        updated_by=incident.updated_by,
        classifications=incident.classifications,
        classification_names=incident.classification_names,
        meanings=incident.meanings,
        labels=incident.labels,
        business_attributes=incident.business_attributes,
        custom_attributes=incident.custom_attributes,
        pending_tasks=incident.pending_tasks,
        proxy=incident.proxy,
        is_incomplete=incident.is_incomplete,
        provenance_type=incident.provenance_type,
        home_id=incident.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _incident_from_nested(nested: IncidentNested) -> Incident:
    """Convert nested format to flat Incident."""
    attrs = (
        nested.attributes if nested.attributes is not UNSET else IncidentAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _INCIDENT_REL_FIELDS,
        IncidentRelationshipAttributes,
    )
    return Incident(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_incident_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _incident_to_nested_bytes(incident: Incident, serde: Serde) -> bytes:
    """Convert flat Incident to nested JSON bytes."""
    return serde.encode(_incident_to_nested(incident))


def _incident_from_nested_bytes(data: bytes, serde: Serde) -> Incident:
    """Convert nested JSON bytes to flat Incident."""
    nested = serde.decode(data, IncidentNested)
    return _incident_from_nested(nested)


